import{_ as e,c as n,a,o as i}from"./app-CEcM0piI.js";const t={};function l(r,s){return i(),n("div",null,s[0]||(s[0]=[a(`<p>&lt;regex&gt;</p><table><thead><tr><th>类或函数名</th><th>作用</th></tr></thead><tbody><tr><td>regex</td><td>表示有一个正则表达式类，比如：regex pattern(&quot;(.{3})(.{2})_(\\d{4})!&quot;)</td></tr><tr><td>regex_match</td><td>全文匹配，要求整个字符串符合正则表达式的匹配规则。用来判断一个字符串和一个正则表达式是否模式匹配，返回一个 bool 值，true 为匹配，false 为不匹配。匹配的含义是目标字符串必须完全和正则表达式相匹配，不能有多余的字符，如果需要部分匹配则应使用regex_search</td></tr><tr><td>regex_search</td><td>搜索匹配，根据正则表达式来搜索字符串中是否存在符合规则的子字符串。 能和正则表达式相匹配就返回true</td></tr><tr><td>regex_replace</td><td>替换匹配，即可以将符合匹配规则的子字符串替换为其他字符串。要求输入一个正则表达式，以及一个用于替换匹配子字符串的格式化字符串。这个格式化字符串可以通过转义序列引用匹配子字符串中的部分内容</td></tr><tr><td>sregex_iterator</td><td>迭代器适配器，调用regex_search来遍历一个string中所有匹配的子串</td></tr><tr><td>smatch/match_results</td><td>容器类，保存在string中搜索的结果。如果匹配成功，这些函数将成功匹配的相关信息保存在给定的smatch对象中。比如：smatch results；将匹配结果存放在results中，另一种存储方法声明：match_results<a href="string::const_iterator" target="_blank" rel="noopener noreferrer">string::const_iterator</a> result</td></tr></tbody></table><p>1、regex库组件使用准备 //头文件包含</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#include&lt;regex&gt;</span></span>
<span class="line"><span>#include&lt;iostream&gt;</span></span>
<span class="line"><span>using namespace std;</span></span>
<span class="line"><span>//匹配结果存放声明</span></span>
<span class="line"><span>smatch results;  //match_results&lt;string::const_iterator&gt; results;是第二种存储方法</span></span>
<span class="line"><span>//匹配字符串和正则pattern准备</span></span>
<span class="line"><span>string str = &quot;2019年12月看的电视hhhhh大亨堡是不是小七的最好吃，你信不信啊?&quot;;</span></span>
<span class="line"><span>string pattern(&quot;(会不会|是不是|能不能|信不信)&quot;);</span></span>
<span class="line"><span>regex r(pattern);   //regex 表示一个正则表达式类</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>2、regex_match使用 （1）输出一个字符序列和一个正则表达式的匹配结果</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>cout &lt;&lt; regex_match(str, results, r) &lt;&lt; endl;  //输出结果为：0</span></span>
<span class="line"><span>if (regex_match(str, results, r))</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>	cout&lt;&lt;results[0]&lt;&lt;endl;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>（2）regex::icase表示匹配时忽略大小写</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>cout&lt;&lt;regex_match(&quot;aaaAAA&quot;, regex(&quot;a*&quot;, regex::icase)) &lt;&lt; endl;  //结果为1</span></span>
<span class="line"><span>cout &lt;&lt; regex_match(&quot;aaaAAA&quot;, regex(&quot;a*&quot;)) &lt;&lt; endl; //结果为0</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>3、regex_search使用 （1）输出第一个与正则表达式匹配的子序列结果</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>cout &lt;&lt; regex_search(str, results, r) &lt;&lt; endl;  //输出结果为1</span></span>
<span class="line"><span>if (regex_search(str, results, r))</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>	cout &lt;&lt; results[0] &lt;&lt; endl;   //输出结果为：是不是</span></span>
<span class="line"><span>	cout &lt;&lt; results.str() &lt;&lt; endl;   //result[]与result.str()这两种方式能够获得相同的值</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>（2）利用迭代器访问到所有匹配的结果值</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>[string::const_iterator iterStart = str.begin(); //迭代器声明</span></span>
<span class="line"><span>string::const_iterator iterEnd = str.end();</span></span>
<span class="line"><span>string temp;</span></span>
<span class="line"><span>while (regex_search(iterStart,iterEnd,results,r))</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>	temp = results[0];</span></span>
<span class="line"><span>	cout &lt;&lt; temp &lt;&lt; endl;   </span></span>
<span class="line"><span>	iterStart = results[0].second; //更新搜索起始位置，搜索剩下的字符串</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>输出结果为：是不是，信不信</p><p>4、regex_replace使用 （1）字符串替换匹配</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>cout &lt;&lt; regex_replace(str, r, &quot;hello&quot;) &lt;&lt; endl;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>输出结果为：2019年12月看的电视hhhhh大亨堡hello小七的最好吃，你hello啊?</p><p>（2）使用regex_replace()函数调整字符串的内容和顺序</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>string str2 = &quot;Hello_2019!&quot;;</span></span>
<span class="line"><span>regex r2(&quot;(.{3})(.{2})_(\\\\d{4})!&quot;);  //匹配3个任意字符+2个任意字符+下划线+4个数字+!</span></span>
<span class="line"><span>cout &lt;&lt; regex_replace(str2, r2, &quot;$1$3&quot;) &lt;&lt; endl;	//输出：Hel2019，将字符串替换为第一个和第三个表达式匹配的内容</span></span>
<span class="line"><span>cout &lt;&lt; regex_replace(str2, r2, &quot;$1$3$2&quot;) &lt;&lt; endl;	//输出：Hel2019lo，交换位置顺序</span></span>
<span class="line"><span>5、sregex_iterator使用</span></span>
<span class="line"><span>//利用sregex_iterator迭代器.它将反复调用regex_search()来寻找文件中的所有匹配</span></span>
<span class="line"><span>for (sregex_iterator it(str.begin(), str.end(), r), end_it; it != end_it; ++it)</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>	cout &lt;&lt; it-&gt;str() &lt;&lt; endl;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>输出结果为：是不是，信不信</p>`,19)]))}const p=e(t,[["render",l]]),c=JSON.parse('{"path":"/cpp/cpp/11/","title":"11、正则库","lang":"zh-CN","frontmatter":{"title":"11、正则库","createTime":"2025/06/18 20:43:44","permalink":"/cpp/cpp/11/"},"readingTime":{"minutes":3.11,"words":932},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/C++/C++/11、正则库.md","headers":[]}');export{p as comp,c as data};
